export const getGetEarningsChartUrl = (params?: GetEarningsChartParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/dashboard/earnings-chart?${stringifiedParams}` : `/api/dashboard/earnings-chart`
}

